import React, { useEffect, useState } from "react";
import api from "../api";
import "./DatabaseViewer.css";

export default function DatabaseViewer({ username, onLogout }) {
  const [activeTab, setActiveTab] = useState("users");
  const [data, setData] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    setError("");
    try {
      console.log(`Loading data for tab: ${activeTab}`);

      let endpoint = "";
      switch (activeTab) {
        case "users":
          endpoint = "/admin/users";
          break;
        case "kyc":
          endpoint = "/admin/kyc";
          break;
        case "checkbooks":
          endpoint = "/admin/checkbook-requests";
          break;
        case "loans":
          endpoint = "/admin/loans";
          break;
        case "transactions":
          endpoint = "/transactions";
          break;
        default:
          endpoint = "/admin/users";
      }

      console.log(`Making request to: ${endpoint}`);
      const response = await api.get(endpoint, {
        params: activeTab === "loans" || activeTab === "transactions" ? { username: "john_doe" } : {}
      });

      console.log(`Response received:`, response.data);
      setData(response.data);
    } catch (err) {
      console.error(`Error loading ${activeTab}:`, err);
      setError(`Error loading ${activeTab}: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  const renderUsers = () => (
    <div className="table-container">
      <h3>👥 All Users</h3>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Username</th>
            <th>Role</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {Array.isArray(data) && data.map((user) => (
            <tr key={user.id}>
              <td>{user.id}</td>
              <td>{user.username}</td>
              <td>
                <span className={`role-badge ${user.role ? user.role.toLowerCase() : 'user'}`}>
                  {user.role || 'USER'}
                </span>
              </td>
              <td>
                <button onClick={() => alert(`View details for ${user.username}`)}>
                  View Details
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderKyc = () => (
    <div className="table-container">
      <h3>📋 KYC Applications</h3>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>User</th>
            <th>Aadhaar</th>
            <th>PAN</th>
            <th>Address</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {Array.isArray(data) && data.map((kyc) => (
            <tr key={kyc.id}>
              <td>{kyc.id}</td>
              <td>{kyc.username || 'N/A'}</td>
              <td>{kyc.aadhaarNumber}</td>
              <td>{kyc.panNumber}</td>
              <td>{kyc.address}</td>
              <td>
                <span className={`status-badge ${kyc.status ? kyc.status.toLowerCase() : 'pending'}`}>
                  {kyc.status || 'PENDING'}
                </span>
              </td>
              <td>
                {(kyc.status === "PENDING") && (
                  <>
                    <button onClick={() => handleKycAction(kyc.id, "approve")}>
                      ✅ Approve
                    </button>
                    <button onClick={() => handleKycAction(kyc.id, "reject")}>
                      ❌ Reject
                    </button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderTransactions = () => (
    <div className="table-container">
      <h3>💳 Transactions</h3>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Timestamp</th>
            <th>Type</th>
            <th>Amount</th>
            <th>Description</th>
          </tr>
        </thead>
        <tbody>
          {Array.isArray(data) && data.map((transaction) => (
            <tr key={transaction.id}>
              <td>{transaction.id}</td>
              <td>{transaction.timestamp}</td>
              <td>
                <span className={`type-badge ${transaction.type ? transaction.type.toLowerCase() : 'credit'}`}>
                  {transaction.type || 'CREDIT'}
                </span>
              </td>
              <td>₹{transaction.amount}</td>
              <td>{transaction.description}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderLoans = () => (
    <div className="table-container">
      <h3>💰 Loans</h3>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Principal</th>
            <th>Interest Rate</th>
            <th>Tenure</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {Array.isArray(data) && data.map((loan) => (
            <tr key={loan.id}>
              <td>{loan.id}</td>
              <td>₹{loan.principal}</td>
              <td>{loan.interestRate}%</td>
              <td>{loan.tenureMonths} months</td>
              <td>
                <span className={`status-badge ${loan.status ? loan.status.toLowerCase() : 'pending'}`}>
                  {loan.status || 'PENDING'}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderCheckbooks = () => (
    <div className="table-container">
      <h3>📬 Checkbook Requests</h3>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Account Number</th>
            <th>Request Date</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {Array.isArray(data) && data.map((checkbook) => (
            <tr key={checkbook.id}>
              <td>{checkbook.id}</td>
              <td>{checkbook.accountNumber || "N/A"}</td>
              <td>{checkbook.requestDate}</td>
              <td>
                <span className={`status-badge ${checkbook.status?.toLowerCase()}`}>
                  {checkbook.status}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const handleKycAction = async (id, action) => {
    try {
      const reviewData = {
        reviewedBy: username,
        comments: `${action}d by admin`,
        reason: action === "reject" ? "Rejected by admin" : ""
      };

      await api.post(`/admin/kyc/${id}/${action}`, reviewData);
      alert(`KYC ${action}d successfully!`);
      loadData();
    } catch (err) {
      alert(`Failed to ${action} KYC: ${err.message}`);
    }
  };

  const renderContent = () => {
    if (loading) return <div className="loading">Loading {activeTab} data...</div>;
    if (error) return <div className="error">❌ {error}</div>;

    // Check if data is empty or undefined
    if (!data || (Array.isArray(data) && data.length === 0)) {
      return <div className="error">⚠️ No {activeTab} data available</div>;
    }

    switch (activeTab) {
      case "users":
        return renderUsers();
      case "kyc":
        return renderKyc();
      case "transactions":
        return renderTransactions();
      case "loans":
        return renderLoans();
      case "checkbooks":
        return renderCheckbooks();
      default:
        return renderUsers();
    }
  };

  return (
    <div className="database-viewer">
      <header className="top-bar">
        <div>
          <h1>🗄️ Database Viewer</h1>
          <p className="subtitle">Logged in as {username}</p>
        </div>
        <button onClick={onLogout}>Logout</button>
      </header>

      <div className="tabs">
        <button
          className={`tab ${activeTab === "users" ? "active" : ""}`}
          onClick={() => setActiveTab("users")}
        >
          👥 Users
        </button>
        <button
          className={`tab ${activeTab === "kyc" ? "active" : ""}`}
          onClick={() => setActiveTab("kyc")}
        >
          📋 KYC
        </button>
        <button
          className={`tab ${activeTab === "transactions" ? "active" : ""}`}
          onClick={() => setActiveTab("transactions")}
        >
          💳 Transactions
        </button>
        <button
          className={`tab ${activeTab === "loans" ? "active" : ""}`}
          onClick={() => setActiveTab("loans")}
        >
          💰 Loans
        </button>
        <button
          className={`tab ${activeTab === "checkbooks" ? "active" : ""}`}
          onClick={() => setActiveTab("checkbooks")}
        >
          📬 Checkbooks
        </button>
      </div>

      <div className="content">
        {renderContent()}
      </div>
    </div>
  );
}
